function isValidRefName(refName) {
	if (refName === '' || (refName[0] === '.' && refName.length > 1)) {
		return false;
	}
	for (let i = 0; i < refName.length; i++) {
		if (!(/[a-zA-Z0-9.-]/).test(refName[i])) {
			return false;
		}
	}
	return true;
}

