class Solution:
    def is_valid_ref_name(self, ref_name: str) -> bool:
        if ref_name == '' or (ref_name[0] == '.' and len(ref_name) > 1):
            return False
        for char in ref_name:
            if not (char.isalnum() or char in ['.', '-']):
                return False
        return True
